pii a[505];
int dis[205][205];
const int DIF = 100;
void solve(int CASE)
{
	int n; cin >> n;
	fa(i, 0, 200)fa(j, 0, 200)dis[i][j] = INF;
	var Q = queue<tuple<int, int, int>>();
	fa(i, 1, n) {
		cin >> a[i].px >> a[i].py;
		Q.push({ a[i].px, a[i].py, dis[a[i].px + DIF][a[i].py + DIF] = 1 });
	}
	while (Q.size()) {
		var[x, y, d] = Q.front();
		Q.pop();
		if (d > dis[x + DIF][y + DIF])continue;
		fa(i, 1, n) {
			const var& [xx, yy] = a[i];
			int nx = xx + x, ny = yy + y;
			if (nx > 100 or ny > 100 or nx < 0 or ny < 0)continue;
			if (dis[nx + DIF][ny + DIF] > dis[x + DIF][y + DIF] + 1) {
				dis[nx + DIF][ny + DIF] = dis[x + DIF][y + DIF] + 1;
				Q.push({ nx,ny,dis[nx + DIF][ny + DIF] });
			}
		}
	}
	if (dis[DIF][DIF] >= INF)cout << -1 << endl;
	else cout << dis[DIF][DIF] << endl;
	return;
}
